module.render:
const color = args.color || 'var(--accent-color)';
const align = (args.align || 'center').toLowerCase();
const textAlign = align === 'left' ? 'left' : align === 'right' ? 'right' : 'center';
const numSize = (args.numbersize && String(args.numbersize).trim()) || '3.5em';
const trend = (args.trend || 'none').toLowerCase();
const arrow = trend === 'up' ? '<span class="bignumber-trend" style="color:#16a34a;">&#9650;</span> '
  : trend === 'down' ? '<span class="bignumber-trend" style="color:#dc2626;">&#9660;</span> ' : '';
const numberStr = sections[0] ? sections[0].trim() : '';
const labelStr = sections[1] ? sections[1].trim() : '';
const captionStr = sections[2] ? sections[2].trim() : '';
let labelVar = '';
if (args.labelcolor && String(args.labelcolor).trim()) labelVar = ' --bn-label:' + String(args.labelcolor).trim() + ';';
let html = `\n\n<div class="mdp-mod-bignumber" style="text-align:${textAlign};${labelVar}">`;
html += `<div class="bignumber-value" style="color: ${color}; font-size: ${numSize};">${arrow}${numberStr}</div>`;
if (labelStr) html += `<div class="bignumber-label">${labelStr}</div>`;
if (captionStr) html += `<div class="bignumber-caption">${captionStr}</div>`;
html += `</div>\n\n`;
return html;
